FUNCTION GenerateViewMatrix(VRP, VPN, VUP):
 // Step 1: Translation to move VRP to origin
 T = TranslateMatrix(-VRP.x, -VRP.y, -VPN.z)

 // Step 2: Rotation to align VPN with -Z axis
 // Compute temporary axis
 R = RotationMatrix(tempX, tempY, tempZ)

 // Step 3: Ensure VUP aligns with Y after rotation
 // Combine transformations
 ViewMatrix = T * R

 RETURN ViewMatrix

// Usage
viewMatrix = GenerateViewMatrix(
 VRP = (0, 0, 10),
 VPN = (0, 0, -1),
 VUP = (0, 1, 0)
)
worldPoint = Transform(worldPoint, viewMatrix)

FUNCTION PerspectiveMatrix(fov, aspect, near, far):
 // fov: field of view angle
 // aspect: width/height ratio
 // near, far: clipping planes

 f = 1.0 / tan(fov / 2.0)

 // Build perspective transformation matrix
 matrix[0][0] = f / aspect
 matrix[1][1] = f
 matrix[2][2] = (far + near) / (near - far)
 matrix[2][3] = (2 * far * near) / (near - far)
 matrix[3][2] = -1.0
 matrix[3][3] = 0.0

 RETURN matrix

// Usage
projMatrix = PerspectiveMatrix(
 fov = 60 degrees,
 aspect = 16/9,
 near = 0.1,
 far = 100.0
)

FUNCTION WindowToViewport(xw, yw, window, viewport):
 // window: {xmin, xmax, ymin, ymax} in world coords
 // viewport: {xmin, xmax, ymin, ymax} in screen coords

 // Calculate scaling factors
 sx = (viewport.xmax - viewport.xmin) / (window.xmax - window.xmin)
 sy = (viewport.ymax - viewport.ymin) / (window.ymax - window.ymin)

 // Calculate translation offsets
 tx = viewport.xmin - window.xmin * sx
 ty = viewport.ymin - window.ymin * sy

 // Transform point
 xv = xw * sx + tx
 yv = yw * sy + ty

 RETURN (xv, yv)

// Example usage
screenPos = WindowToViewport(
 xw = 50, yw = 50,
 window = {xmin: 0, xmax: 100, ymin: 0, ymax: 100},
 viewport = {xmin: 0, xmax: 640, ymin: 0, ymax: 480}
)
